    if (status.stat === "attack") return status.value >= 0 ? "⚔" : "↓";
    if (status.stat === "defense") return status.value >= 0 ? "🛡" : "↓";
    if (status.stat === "speed") return "👢";
    if (status.stat === "damageDealt") return "✦";
    if (status.stat === "damageTaken") return status.value >= 0 ? "☠" : "◇";
